import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleTryCatchAndTypeAliasTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a try expression with catch on a new line in an expression body function`() {
        val code =
            """
            fun test() = try {
              1
            }
            catch(_: Throwable) {
              2
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a typealias with the type on the next line`() {
        val code =
            """
            typealias Foo =
              HashMap<Bar, Baz?>
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasNoLintViolations()
    }
}
"}

